script:
export const meta = {
  name: 'pass9-confirm',
  description: 'Pass-9: two independent agents confirm each of the 5 fixes is appropriate AND complete',
  phases: [{ title: 'Confirm' }],
}
const REPO = '/Users/[REDACTED]/hc-assay'
const SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['verdict', 'appropriate', 'complete', 'rationale', 'concerns'],
  properties: {
    verdict: { type: 'string', enum: ['CONFIRMED', 'CONCERN', 'REJECTED'] },
    appropriate: { type: 'boolean' }, complete: { type: 'boolean' },
    rationale: { type: 'string' }, concerns: { type: 'array', items: { type: 'string' } },
  },
}
const FINDINGS = [
  { key: 'K-SEC-9-1', desc: `SECURITY regression of pass-8's Unix-socket allowance: libpq comma multi-host (host=/tmp,evil.com) was ACCEPTED because the leading-"/" socket check ran on the whole value. Fix in src/assay_engine/_local.py: is_local_socket_path() now returns False if "," in the value; the DSN keyword branch and the URI query branch SPLIT host/hostaddr on "," and validate EVERY element with is_loopback_host OR is_local_socket_path. VERIFY empirically (python): require_local_uri('host=/tmp,evil.com'), 'host=/var/run/postgresql,10.0.0.5', 'postgresql:///db?host=/var/run/postgresql,evil.com' are REJECTED, while single 'host=/var/run/postgresql', 'host=/tmp', 'postgresql://localhost/db', 'host=127.0.0.1' are ACCEPTED, and UNC '//evil/share' still rejected. Test: test_require_local_uri_rejects_multihost_socket_bypass. Confirm it discriminates (reverting the split → bypass accepted → test fails).` },
  { key: 'CI-1', desc: `branch protection unavailable on this plan (private/free → 403), so the all-checks gate is unenforced — nothing blocks a red merge. Remediation is a COMPENSATING CONTROL (enabling protection is out of scope: making the repo public would publish transcripts; plan upgrade is billing): scripts/require_green_ci.sh exits non-zero unless the latest ci run for the branch concluded success; docs/MERGE-POLICY.md documents the constraint + the mandatory pre-merge procedure; the all-checks comment in ci.yml now honestly flags the caveat (#CI-1). Judge whether this is an appropriate + complete response GIVEN the platform constraint (you cannot fix the platform). Test: test_merge_gate_compensating_control_exists. Optionally run the script (gh available) and confirm it exits 0 on a green branch / would exit 1 on red.` },
  { key: 'P9-PII-1', desc: `Operator machine/namespace hostname leaked in committed transcripts ([REDACTED][.local], [REDACTED]), no scrub rule. Fix in scripts/capture_transcripts.py: _hostname_patterns() derives the MACHINE hostname (socket.gethostname/platform.node/scutil) → redacts bare + ".local"; ASSAY_SCRUB_HOSTS entries → redact ONLY the ".local" form (bare project token like hc-grc preserved). Applied in _scrub. The committed corpus was re-scrubbed. VERIFY: grep transcripts/ for [REDACTED] / [REDACTED] / [REDACTED] → 0; bare 'hc-grc' still present (not over-redacted); unrelated 'settings.local.json' untouched. Test: test_scrub_redacts_machine_and_namespace_hostnames. Check the derived machine pattern doesn't over-redact a short/common hostname.` },
  { key: 'P9-MO-1', desc: `confirm primitives raised an opaque TypeError when alpha was locked on NEITHER the hypothesis NOR the call (resolved to None → 0.0 < None). Fix in src/assay_engine/methodology/confirm.py _validate_alpha: reject None with a ValueError naming alpha and how to provide it. VERIFY: verdict_from_pvalue('h', statistic=1.0, p_value=0.01, alpha=None, powered=True, direction_supports_claim=True) raises ValueError (not TypeError) matching "alpha is required". Test: test_alpha_none_raises_clear_valueerror_not_opaque_typeerror. Confirm the existing valid-alpha tests still pass.` },
  { key: 'P9-MO-2', desc: `bare int()/float() parsing of env vars in seam.py (8 sites) and checkpoint.py (4 sites) raised an opaque "invalid literal" naming no var. Fix: new shared src/assay_engine/_envparse.py (int_env/float_env, empty treated as default, ValueError names the var), wired into seam.py + checkpoint.py. VERIFY: a malformed ASSAY_* numeric env raises a ValueError naming the var; seam.py/checkpoint.py no longer have bare int(/float( of os.environ/_env; existing behavior (defaults, monkeypatched _MIGRATION_LOCK_TIMEOUT_MS) preserved. Tests: test_numeric_env_parsing_names_the_bad_var (+ existing persistence/observability int_env tests still pass).` },
]
function prompt(f, lens) {
  return `You are an independent, adversarial fix-confirmation reviewer (reviewer ${lens}) for the hc-assay hardening campaign at ${REPO} (branch harden/pass-9, latest commit). Confirm the fix is BOTH appropriate (correct root cause, sound approach, right layer) AND complete (no residual gap; regression test DISCRIMINATES — fails if reverted). Be skeptical; find holes. For a constrained finding (CI-1) judge the response given the real constraint.\n\nFINDING ${f.key}:\n${f.desc}\n\nRead the changed files and run what you can (cd ${REPO} && source .venv/bin/activate && python -m pytest -q <path>; "python -m pytest" not bare pytest; gh available for CI-1). Judge ONLY ${f.key}. CONFIRMED only if appropriate AND complete; CONCERN if a real residual gap; REJECTED if wrong/non-discriminating. List concrete concerns (empty if none).`
}
phase('Confirm')
const results = await parallel(
  FINDINGS.flatMap((f) => [
    () => agent(prompt(f, 'A'), { label: `confirm:${f.key}:A`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, lens: 'A', v })),
    () => agent(prompt(f, 'B'), { label: `confirm:${f.key}:B`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, lens: 'B', v })),
  ])
)
const clean = results.filter(Boolean)
const byKey = {}
for (const r of clean) { (byKey[r.key] = byKey[r.key] || []).push({ lens: r.lens, ...r.v }) }
const summary = Object.entries(byKey).map(([key, votes]) => ({ key, bothConfirmed: votes.length === 2 && votes.every((x) => x.verdict === 'CONFIRMED'), votes }))
log('PASS-9 FIX CONFIRMATION:')
for (const s of summary) log(`${s.key}: ${s.bothConfirmed ? 'BOTH-CONFIRMED' : 'NEEDS-ATTENTION'} — ${s.votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
return { summary }
